"use strict";
function format(str,args){
  return str.replace(/%s/g,()=> String(args.shift() ?? ''));
}
function createY18n(){
  let locale='en';
  const translations={};
  return {
    __(str,...args){ const t=(translations[locale]&&translations[locale][str])||str; return format(t,args); },
    __n(singular, plural, quantity, ...args){ const key=Number(quantity)===1?singular:plural; const t=(translations[locale]&&translations[locale][key])||key; return format(t,[quantity,...args]); },
    setLocale(l){ locale=l; },
    getLocale(){ return locale; },
    updateLocale(obj){ translations[locale]={...(translations[locale]||{}), ...(obj||{})}; }
  };
}
module.exports = createY18n;
module.exports.default = createY18n;
